parameters.jsCode:
const storyData = $('Set Story Input').first().json;
const story = storyData.story || '';

// Get form fields directly from the form trigger
let title = '';
let description = '';
let ac = '';

try {
  const formData = $('On form submission').first().json;
  title = formData['Story title'] || '';
  description = formData['Story description'] || '';
  ac = formData['Acceptance criteria'] || '';
} catch(e) {
  // fallback — parse from story string if form data not available
  const lines = story.split('\n');
  title = lines[0].replace('Title: ', '').trim();
  description = lines[1] ? lines[1].replace('Description: ', '').trim() : '';
}

// Hard validation checks — runs before calling AI
const titleWords = title.trim().split(/\s+/).filter(w => w.length > 0).length;
const descWords = description.trim().split(/\s+/).filter(w => w.length > 0).length;
const acLines = ac.trim().split('\n').filter(l => l.trim().length > 3).length;

if (titleWords === 0) {
  return [{
    json: {
      validation_status: 'FAIL',
      is_pass: false,
      is_fail: true,
      route: 'fail',
      validator_feedback: 'Story title is missing. Please add a clear title describing what was built and resubmit.',
      story: story,
      run_id: storyData.run_id,
      pipeline_start_time: storyData.pipeline_start_time
    }
  }];
}

if (descWords < 10) {
  return [{
    json: {
      validation_status: 'FAIL',
      is_pass: false,
      is_fail: true,
      route: 'fail',
      validator_feedback: 'Description is too short or missing. Please write at least 2-3 sentences explaining what was built and why, then resubmit.',
      story: story,
      run_id: storyData.run_id,
      pipeline_start_time: storyData.pipeline_start_time
    }
  }];
}

if (acLines < 3) {
  return [{
    json: {
      validation_status: 'FAIL',
      is_pass: false,
      is_fail: true,
      route: 'fail',
      validator_feedback: 'At least 3 acceptance criteria are required. Please add specific testable criteria (one per line) and resubmit.',
      story: story,
      run_id: storyData.run_id,
      pipeline_start_time: storyData.pipeline_start_time
    }
  }];
}

// Story passed hard checks — now read AI validator result
const content = $input.first().json.message.content;

let status;
if (typeof content === 'string') {
  status = JSON.parse(content).status;
} else {
  status = content.status;
}

status = String(status).trim().toUpperCase();

const isPASS = status === 'PASS';

let feedbackMessage = '';
try {
  const parsed = typeof content === 'string' ? JSON.parse(content) : content;
  feedbackMessage = parsed.feedback_to_developer || '';
} catch(e) {
  feedbackMessage = 'Please review your story and resubmit.';
}

return [{
  json: {
    validation_status: status,
    is_pass: isPASS === true,
    is_fail: isPASS !== true,
    route: isPASS ? 'pass' : 'fail',
    validator_feedback: feedbackMessage,
    story: story,
    run_id: storyData.run_id,
    pipeline_start_time: storyData.pipeline_start_time
  }
}];

